#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=2e2+5,MAXM=3e4+5;
int n,maxx,a[MAXN],f[MAXM],T,ans;
int main(void){
	T=read();
	while(T--){
		ans=maxx=0;
		memset(f,-0x3f,sizeof(f));
		f[0]=0;
		n=read();
		for(int i=1;i<=n;++i)
		{
			maxx=max(maxx,a[i]=read());
		}
		for(int i=1;i<=n;++i)
		{
			for(int j=a[i];j<=maxx;++j)
			{
				f[j]=max(f[j],f[j-a[i]]+1);
			}
		}
		for(int i=1;i<=n;++i)
		{
			ans+=(f[a[i]]==1);
		}
		write(ans);
		puts("");
	}
	return false;
}
